#!/usr/bin/env node
/**
 * agent-tier-guard.mjs — PreToolUse hook enforcing per-tier permissions.
 *
 * Reads tool-call event JSON from stdin (standard Claude Code hook contract):
 *   { "tool_name": "Edit"|"Write"|"Bash"|..., "tool_input": {...}, ... }
 *
 * Looks up `process.env.CLAUDE_AGENT_NAME` against `.claude/agents/manifest.json`
 * (generated by `tools/scripts/build-agent-manifest.mjs`).
 *
 * Tier A (read-only) — RAM ceiling 300MB, no concurrent cap:
 *   - Edit/Write blocked outside `.specify/**` and
 *     `apps/project-tracker/docs/metrics/**`.
 *   - Bash blocked when invoking `pnpm test|build|dev` or `npx vitest run`
 *     without `--coverage.include=` scoping (heavy unscoped operations).
 *
 * Tier B/C — no extra restrictions imposed here (the orchestrator caps
 *   concurrency separately).
 *
 * Main agent (no CLAUDE_AGENT_NAME) — no tier checks; always allow.
 *
 * Exit codes:
 *   0 = allow
 *   2 = block (Claude Code stops the tool call and shows stderr)
 */

import { readFileSync, existsSync } from 'node:fs';
import { join, dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

async function readStdin() {
  let data = '';
  for await (const chunk of process.stdin) data += chunk;
  return data;
}

function findRepoRoot(start) {
  let cur = resolve(start);
  for (let i = 0; i < 10; i++) {
    if (existsSync(join(cur, '.claude', 'agents', 'manifest.json'))) return cur;
    const parent = dirname(cur);
    if (parent === cur) break;
    cur = parent;
  }
  return start;
}

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = findRepoRoot(resolve(here, '..', '..'));

(async () => {
  const agent = process.env.CLAUDE_AGENT_NAME;
  if (!agent) process.exit(0);

  const manifestPath = join(repoRoot, '.claude', 'agents', 'manifest.json');
  if (!existsSync(manifestPath)) process.exit(0);

  let manifest;
  try {
    manifest = JSON.parse(readFileSync(manifestPath, 'utf8'));
  } catch {
    process.exit(0);
  }

  const entry = manifest.agents?.find?.((a) => a.name === agent);
  if (!entry) process.exit(0);

  const tier = entry.tier;
  const raw = await readStdin();
  if (!raw) process.exit(0);

  let event;
  try {
    event = JSON.parse(raw);
  } catch {
    process.exit(0);
  }

  const toolName = event.tool_name || '';
  const input = event.tool_input || {};

  if (tier === 'A') {
    if (toolName === 'Edit' || toolName === 'Write') {
      const fp = String(input.file_path || '').replace(/\\/g, '/');
      const allowed =
        fp.includes('/.specify/') ||
        fp.startsWith('.specify/') ||
        fp.includes('apps/project-tracker/docs/metrics/');
      if (!allowed) {
        process.stderr.write(
          `BLOCK [agent-tier-guard]: tier-A agent "${agent}" cannot ${toolName} outside .specify/ or apps/project-tracker/docs/metrics/. Path: ${fp}\n`
        );
        process.exit(2);
      }
    }
    if (toolName === 'Bash') {
      const cmd = String(input.command || '');
      const heavy =
        /\bpnpm\s+(?:test|build|dev)\b/.test(cmd) || /\bnpx\s+vitest\s+run\b/.test(cmd);
      const scoped = /--coverage\.include=/.test(cmd);
      if (heavy && !scoped) {
        process.stderr.write(
          `BLOCK [agent-tier-guard]: tier-A agent "${agent}" cannot run unscoped pnpm test/build/dev or vitest. Add --coverage.include=<glob> to scope.\n`
        );
        process.exit(2);
      }
    }
  }

  process.exit(0);
})();
